diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9ff1e3aa5502..4c9ef1c115fc 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -5255,6 +5255,273 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
       return new ICmpInst(ICmpInst::getSignedPredicate(Pred),
                           Constant::getNullValue(Op0->getType()), Op0);
   }
+  // icmp {s/u}{lt/le/gt/ge} ([su]div X, C), X where C > 1
+  // For signed division with C > 1:
+  //   icmp slt (sdiv X, C), X --> icmp sgt X, 0  (true only when X > 0)
+  //   icmp sle (sdiv X, C), X --> icmp sge X, 0  (true when X >= 0)
+  //   icmp sgt (sdiv X, C), X --> icmp slt X, 0  (true only when X < 0)
+  //   icmp sge (sdiv X, C), X --> icmp sle X, 0  (true when X <= 0)
+  // For unsigned division with C > 1:
+  //   icmp ult (udiv X, C), X --> icmp ne X, 0   (true when X != 0)
+  //   icmp ule (udiv X, C), X --> true           (always true)
+  //   icmp ugt (udiv X, C), X --> false          (never true)
+  //   icmp uge (udiv X, C), X --> icmp eq X, 0   (true only when X == 0)
+  if (BO0 && (BO0->getOpcode() == Instruction::SDiv ||
+              BO0->getOpcode() == Instruction::UDiv)) {
+    Value *Dividend = BO0->getOperand(0);
+    Value *Divisor = BO0->getOperand(1);
+    if (Dividend == Op1) {
+      const APInt *C;
+      if (match(Divisor, m_APInt(C)) && C->isStrictlyPositive() && !C->isOne()) {
+        Type *Ty = Dividend->getType();
+        if (BO0->getOpcode() == Instruction::SDiv) {
+          switch (Pred) {
+          case ICmpInst::ICMP_SLT:
+            return new ICmpInst(ICmpInst::ICMP_SGT, Dividend,
+                               Constant::getNullValue(Ty));
+          case ICmpInst::ICMP_SLE:
+            return new ICmpInst(ICmpInst::ICMP_SGE, Dividend,
+                               Constant::getNullValue(Ty));
+          case ICmpInst::ICMP_SGT:
+            return new ICmpInst(ICmpInst::ICMP_SLT, Dividend,
+                               Constant::getNullValue(Ty));
+          case ICmpInst::ICMP_SGE:
+            return new ICmpInst(ICmpInst::ICMP_SLE, Dividend,
+                               Constant::getNullValue(Ty));
+          case ICmpInst::ICMP_EQ:
+            return new ICmpInst(ICmpInst::ICMP_EQ, Dividend,
+                               Constant::getNullValue(Ty));
+          case ICmpInst::ICMP_NE:
+            return new ICmpInst(ICmpInst::ICMP_NE, Dividend,
+                               Constant::getNullValue(Ty));
+          default:
+            break;
+          }
+        } else { // UDiv
+          switch (Pred) {
+          case ICmpInst::ICMP_ULT:
+            return new ICmpInst(ICmpInst::ICMP_NE, Dividend,
+                               Constant::getNullValue(Ty));
+          case ICmpInst::ICMP_ULE:
+            return replaceInstUsesWith(I, ConstantInt::getTrue(Ty));
+          case ICmpInst::ICMP_UGT:
+            return replaceInstUsesWith(I, ConstantInt::getFalse(Ty));
+          case ICmpInst::ICMP_UGE:
+            return new ICmpInst(ICmpInst::ICMP_EQ, Dividend,
+                               Constant::getNullValue(Ty));
+          case ICmpInst::ICMP_EQ:
+            return new ICmpInst(ICmpInst::ICMP_EQ, Dividend,
+                               Constant::getNullValue(Ty));
+          case ICmpInst::ICMP_NE:
+            return new ICmpInst(ICmpInst::ICMP_NE, Dividend,
+                               Constant::getNullValue(Ty));
+          case ICmpInst::ICMP_SLT:
+            return new ICmpInst(ICmpInst::ICMP_SGT, Dividend,
+                               Constant::getNullValue(Ty));
+          case ICmpInst::ICMP_SLE:
+            return replaceInstUsesWith(I, ConstantInt::getTrue(Ty));
+          case ICmpInst::ICMP_SGT:
+            return replaceInstUsesWith(I, ConstantInt::getFalse(Ty));
+          case ICmpInst::ICMP_SGE:
+            return new ICmpInst(ICmpInst::ICMP_EQ, Dividend,
+                               Constant::getNullValue(Ty));
+          default:
+            break;
+          }
+        }
+      }
+    }
+  }
+  // icmp {s/u}{lt/le/gt/ge} X, ([su]div X, C) where C > 1
+  // Similar patterns when operands are swapped
+  if (BO1 && (BO1->getOpcode() == Instruction::SDiv ||
+              BO1->getOpcode() == Instruction::UDiv)) {
+    Value *Dividend = BO1->getOperand(0);
+    Value *Divisor = BO1->getOperand(1);
+    if (Dividend == Op0) {
+      const APInt *C;
+      if (match(Divisor, m_APInt(C)) && C->isStrictlyPositive() && !C->isOne()) {
+        Type *Ty = Dividend->getType();
+        if (BO1->getOpcode() == Instruction::SDiv) {
+          switch (Pred) {
+          case ICmpInst::ICMP_SLT:
+            return new ICmpInst(ICmpInst::ICMP_SLT, Dividend,
+                               Constant::getNullValue(Ty));
+          case ICmpInst::ICMP_SLE:
+            return new ICmpInst(ICmpInst::ICMP_SLE, Dividend,
+                               Constant::getNullValue(Ty));
+          case ICmpInst::ICMP_SGT:
+            return new ICmpInst(ICmpInst::ICMP_SGT, Dividend,
+                               Constant::getNullValue(Ty));
+          case ICmpInst::ICMP_SGE:
+            return new ICmpInst(ICmpInst::ICMP_SGE, Dividend,
+                               Constant::getNullValue(Ty));
+          case ICmpInst::ICMP_EQ:
+            return new ICmpInst(ICmpInst::ICMP_EQ,
+                               Constant::getNullValue(Ty), Dividend);
+          case ICmpInst::ICMP_NE:
+            return new ICmpInst(ICmpInst::ICMP_NE,
+                               Constant::getNullValue(Ty), Dividend);
+          default:
+            break;
+          }
+        } else { // UDiv
+          switch (Pred) {
+          case ICmpInst::ICMP_ULT:
+            return new ICmpInst(ICmpInst::ICMP_NE,
+                               Constant::getNullValue(Ty), Dividend);
+          case ICmpInst::ICMP_ULE:
+            return replaceInstUsesWith(I, ConstantInt::getFalse(Ty));
+          case ICmpInst::ICMP_UGT:
+            return replaceInstUsesWith(I, ConstantInt::getTrue(Ty));
+          case ICmpInst::ICMP_UGE:
+            return new ICmpInst(ICmpInst::ICMP_EQ,
+                               Constant::getNullValue(Ty), Dividend);
+          case ICmpInst::ICMP_EQ:
+            return new ICmpInst(ICmpInst::ICMP_EQ,
+                               Constant::getNullValue(Ty), Dividend);
+          case ICmpInst::ICMP_NE:
+            return new ICmpInst(ICmpInst::ICMP_NE,
+                               Constant::getNullValue(Ty), Dividend);
+          case ICmpInst::ICMP_SLT:
+            return new ICmpInst(ICmpInst::ICMP_SLT, Dividend,
+                               Constant::getNullValue(Ty));
+          case ICmpInst::ICMP_SLE:
+            return new ICmpInst(ICmpInst::ICMP_SLE, Dividend,
+                               Constant::getNullValue(Ty));
+          case ICmpInst::ICMP_SGT:
+            return new ICmpInst(ICmpInst::ICMP_SGT, Dividend,
+                               Constant::getNullValue(Ty));
+          case ICmpInst::ICMP_SGE:
+            return new ICmpInst(ICmpInst::ICMP_SGE, Dividend,
+                               Constant::getNullValue(Ty));
+          default:
+            break;
+          }
+        }
+      }
+    }
+  }
+  // icmp {s/u}{lt/le/gt/ge} (lshr X, C), X where C > 0
+  // For logical shift right with C > 0:
+  //   icmp eq (lshr X, C), X --> icmp eq X, 0
+  //   icmp ne (lshr X, C), X --> icmp ne X, 0
+  //   icmp slt (lshr X, C), X --> icmp sgt X, 0
+  //   icmp sle (lshr X, C), X --> icmp sge X, 0
+  //   icmp sgt (lshr X, C), X --> icmp slt X, 0
+  //   icmp sge (lshr X, C), X --> icmp sle X, 0
+  if (BO0 && BO0->getOpcode() == Instruction::LShr) {
+    Value *ShrVal = BO0->getOperand(0);
+    Value *ShrAmt = BO0->getOperand(1);
+    if (ShrVal == Op1) {
+      const APInt *C;
+      if (match(ShrAmt, m_APInt(C)) && !C->isZero()) {
+        Type *Ty = ShrVal->getType();
+        switch (Pred) {
+        case ICmpInst::ICMP_EQ:
+          return new ICmpInst(ICmpInst::ICMP_EQ, ShrVal,
+                             Constant::getNullValue(Ty));
+        case ICmpInst::ICMP_NE:
+          return new ICmpInst(ICmpInst::ICMP_NE, ShrVal,
+                             Constant::getNullValue(Ty));
+        case ICmpInst::ICMP_SLT:
+          return new ICmpInst(ICmpInst::ICMP_SGT, ShrVal,
+                             Constant::getNullValue(Ty));
+        case ICmpInst::ICMP_SLE:
+          return new ICmpInst(ICmpInst::ICMP_SGE, ShrVal,
+                             Constant::getNullValue(Ty));
+        case ICmpInst::ICMP_SGT:
+          return new ICmpInst(ICmpInst::ICMP_SLT, ShrVal,
+                             Constant::getNullValue(Ty));
+        case ICmpInst::ICMP_SGE:
+          return new ICmpInst(ICmpInst::ICMP_SLE, ShrVal,
+                             Constant::getNullValue(Ty));
+        default:
+          break;
+        }
+      }
+    }
+  }
+  // icmp {s/u}{lt/le/gt/ge} X, (lshr X, C) where C > 0
+  // Similar patterns when operands are swapped
+  if (BO1 && BO1->getOpcode() == Instruction::LShr) {
+    Value *ShrVal = BO1->getOperand(0);
+    Value *ShrAmt = BO1->getOperand(1);
+    if (ShrVal == Op0) {
+      const APInt *C;
+      if (match(ShrAmt, m_APInt(C)) && !C->isZero()) {
+        Type *Ty = ShrVal->getType();
+        switch (Pred) {
+        case ICmpInst::ICMP_EQ:
+          return new ICmpInst(ICmpInst::ICMP_EQ,
+                             Constant::getNullValue(Ty), ShrVal);
+        case ICmpInst::ICMP_NE:
+          return new ICmpInst(ICmpInst::ICMP_NE,
+                             Constant::getNullValue(Ty), ShrVal);
+        case ICmpInst::ICMP_SLT:
+          return new ICmpInst(ICmpInst::ICMP_SLT, ShrVal,
+                             Constant::getNullValue(Ty));
+        case ICmpInst::ICMP_SLE:
+          return new ICmpInst(ICmpInst::ICMP_SLE, ShrVal,
+                             Constant::getNullValue(Ty));
+        case ICmpInst::ICMP_SGT:
+          return new ICmpInst(ICmpInst::ICMP_SGT, ShrVal,
+                             Constant::getNullValue(Ty));
+        case ICmpInst::ICMP_SGE:
+          return new ICmpInst(ICmpInst::ICMP_SGE, ShrVal,
+                             Constant::getNullValue(Ty));
+        default:
+          break;
+        }
+      }
+    }
+  }
+  // icmp {s/u}{lt/le/gt/ge} (ashr X, C), X where C > 0
+  // For arithmetic shift right with C > 0:
+  //   icmp sge (ashr X, C), X --> icmp sle X, 0
+  //   icmp sle (ashr X, C), X --> icmp sge X, 0
+  if (BO0 && BO0->getOpcode() == Instruction::AShr) {
+    Value *ShrVal = BO0->getOperand(0);
+    Value *ShrAmt = BO0->getOperand(1);
+    if (ShrVal == Op1) {
+      const APInt *C;
+      if (match(ShrAmt, m_APInt(C)) && !C->isZero()) {
+        Type *Ty = ShrVal->getType();
+        switch (Pred) {
+        case ICmpInst::ICMP_SLE:
+          return new ICmpInst(ICmpInst::ICMP_SGE, ShrVal,
+                             Constant::getNullValue(Ty));
+        case ICmpInst::ICMP_SGE:
+          return new ICmpInst(ICmpInst::ICMP_SLE, ShrVal,
+                             Constant::getNullValue(Ty));
+        default:
+          break;
+        }
+      }
+    }
+  }
+  // icmp {s/u}{lt/le/gt/ge} X, (ashr X, C) where C > 0
+  if (BO1 && BO1->getOpcode() == Instruction::AShr) {
+    Value *ShrVal = BO1->getOperand(0);
+    Value *ShrAmt = BO1->getOperand(1);
+    if (ShrVal == Op0) {
+      const APInt *C;
+      if (match(ShrAmt, m_APInt(C)) && !C->isZero()) {
+        Type *Ty = ShrVal->getType();
+        switch (Pred) {
+        case ICmpInst::ICMP_SLE:
+          return new ICmpInst(ICmpInst::ICMP_SLE, ShrVal,
+                             Constant::getNullValue(Ty));
+        case ICmpInst::ICMP_SGE:
+          return new ICmpInst(ICmpInst::ICMP_SGE, ShrVal,
+                             Constant::getNullValue(Ty));
+        default:
+          break;
+        }
+      }
+    }
+  }
+

   if (Value *V = foldMultiplicationOverflowCheck(I))
     return replaceInstUsesWith(I, V);

